BEGIN RSA_CRT_DECRYPT(C, d, p, q)
  // Chinese Remainder Theorem optimization
  // Split computation into two smaller moduli

  // Step 1: Compute exponentiations modulo p and q
  dp ← d mod (p - 1)  // For efficiency: reduce exponent
  dq ← d mod (q - 1)

  // Step 2: Compute partial decryptions
  M1 ← MODULAR_EXPONENTIATION(C, dp, p)  // C^d mod p
  M2 ← MODULAR_EXPONENTIATION(C, dq, q)  // C^d mod q

  // Step 3: Precompute CRT combining values
  q_inv ← MODULAR_INVERSE(q, p)  // q⁻¹ mod p

  // Step 4: Combine using CRT formula
  // M = M2 + q × ((M1 - M2) × q⁻¹ mod p)
  h ← ((M1 - M2) × q_inv) mod p
  M ← M2 + q × h

  RETURN M
END

// Additional optimization: Garner algorithm variant
BEGIN RSA_CRT_COMBINE(M1, M2, p, q)
  // Alternative combining method
  t ← (M1 - M2) mod p
  IF t < 0 THEN
    t ← t + p
  END IF

  t ← (t × q_inv) mod p
  M ← M2 + q × t

  RETURN M
END
